import{_ as t,o as n,c as i,a3 as a}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"7. Saving Of Local Agreements","description":"","frontmatter":{"title":"7. Saving Of Local Agreements","eba":"Medical Specialists 2022-2026","topics":["wages"]},"headers":[],"relativePath":"ebas/medical-specialists/preliminary/7-saving-of-local-agreements.md","filePath":"ebas/medical-specialists/preliminary/7-saving-of-local-agreements.md"}'),o={name:"ebas/medical-specialists/preliminary/7-saving-of-local-agreements.md"};function r(s,e,l,c,h,m){return n(),i("div",null,[...e[0]||(e[0]=[a('<h1 id="_7-saving-of-local-agreements" tabindex="-1">7. Saving Of Local Agreements <a class="header-anchor" href="#_7-saving-of-local-agreements" aria-label="Permalink to &quot;7. Saving Of Local Agreements&quot;">​</a></h1><p><strong>7.1</strong> The making of this Agreement is predicated on the expectation and understanding that pre-existing terms and conditions of employment applying prior to the 2013 Specialists Agreement will not be set aside as a result of the implementation of this Agreement.</p><p><strong>7.2</strong> The parties acknowledge that the increases in remuneration provided in <a href="/eba/ebas/medical-specialists/consultation-disputes/13-prevention-and-management-of-workplace-bullying.html">clause 13</a> of the 2013 Specialists Agreement and other benefits provided under that agreement were agreed on the basis that there would be no further claims prior to the nominal expiry date of the 2013 Specialists Agreement, collectively or individually, which would have the effect of increasing the net operating costs of any Health Service above the net costs directly attributable to the implementation of the terms of the 2013 Specialists Agreement. This commitment will continue for the life of this Agreement.</p><p><strong>7.3</strong> The following terms are intended to give effect to this commitment by the parties.</p><p><strong>7.4</strong> Except as provided in <a href="/eba/ebas/medical-specialists/wages/31-remuneration-and-remuneration-increases.html">clause 31</a>, this Agreement does not disturb the continued application of employment entitlements in operation immediately prior to the commencement of the 2013 Specialists Agreement (Pre-existing Entitlements), provided that the Pre-existing Entitlements do not:</p><p><strong>(a)</strong> contravene any law;</p><p><strong>(b)</strong> have the effect, directly or indirectly, of increasing the operating net costs of any Health Service above the net costs directly attributable to the implementation of the terms of this Agreement;</p><p><strong>(c)</strong> derogate from the requirements of this Agreement; or</p><p><strong>(d)</strong> have the effect, directly or indirectly, of providing a monetary benefit to the Doctor inconsistent with (greater or less than) that provided under <a href="/eba/ebas/medical-specialists/wages/31-remuneration-and-remuneration-increases.html">clause 31</a>.</p><p><strong>7.5</strong> Review of Pre-existing Entitlements</p><p><strong>(a)</strong> In the course of bargaining for – and during the term of – the 2018 Agreement, the parties reviewed the certified agreements and enterprise agreements listed in <a href="/eba/ebas/medical-specialists/appendices/5-list-of-local-certified-agreements-and-enterprise-agreements.html">Appendix 5</a> that pertained to Health Services covered by this Agreement and which were in operation immediately prior to the commencement of the 2013 Specialists Agreement (Pre-2013 Collective Agreements). That review identified a number of employment entitlements that have continued application by virtue of <a href="/eba/ebas/medical-specialists/preliminary/6-application-and-relationship-to-the-nes.html">clause 6</a> of the 2013 Specialists Agreement, had continued application by virtue of clause 7 of the 2018 Agreement and will have continued application by virtue of this clause.</p><p><strong>(b)</strong> The parties continue to acknowledge and agree that:</p><p><strong>(i)</strong> the purpose of the Review conducted in connection with the 2018 Agreement was to provide clarity in relation to Pre-existing Entitlements (that is, employment entitlements in operation immediately prior to the commencement of the 2013 Specialists Agreement) that stem from the Pre-2013 Collective Agreements and the relevant Heads of Agreement and that have continued application by virtue of this clause, in respect of each of the Health Services covered by one or more of the Pre-2013 Collective Agreements;</p><p><strong>(ii)</strong> subject to the requirements of the Act, the intent was to develop Health Service specific Schedules which contain Pre-existing Entitlements and for those Schedules to be implemented by way of a variation to this Agreement;</p><p><strong>(iii)</strong> there may have been variations to employment entitlements based on local negotiations which have had the effect of replacing or superseding terms and conditions contained in the Pre-2013 Collective Agreements and such outcomes were:</p><p>A. considered in the course of the Review; and</p><p>B. included in any applicable Health Service specific Schedule, where relevant and provided the overall conditions of the relevant group of Doctors reflected in the Agreement and the relevant Schedule are equal to or better off overall.</p><p><strong>(iv)</strong> it was not intended that a Doctor would or will receive the benefit of two payments in satisfaction for the same work and where there were or are separate entitlements in the 2018 Agreement or this Agreement and any Health Service specific Schedule, only the most beneficial entitlement will apply;</p><p><strong>(v)</strong> the Pre-2013 Collective Agreements are not incorporated into and do not form part of this Agreement; and</p><p><strong>(vi)</strong> If a dispute arises during the course of the Review, the parties agree to seek the assistance of the FWC to facilitate and/or determine an outcome to the disputed matter.</p><p><strong>(c)</strong> Where the Review referred to at 7.5(a) or further review referred to at 7.6 is agreed to be concluded, the Pre-Existing Entitlements will be reduced to writing and exchanged between the Health Service, the Association and VHIA along with confirmation that the Review is complete.</p><p><strong>7.6</strong> Except as provided in <a href="/eba/ebas/medical-specialists/wages/31-remuneration-and-remuneration-increases.html">clause 31</a>, this Agreement is not intended to prevent a Health Service from initiating a further review of Pre-existing Entitlements, on the basis that the outcome of such a review must:</p><p><strong>(a)</strong> prior to its implementation, be agreed between the Health Service and a majority of its relevant Doctors; and</p><p><strong>(b)</strong> not offend any of the requirements at clauses 7.4(a) to (d) above.</p>',24)])])}const g=t(o,[["render",r]]);export{d as __pageData,g as default};
